#include <iostream>
#include <iomanip>
#include <vector>
#include <string>

using namespace std;

// Function to generate a sequence of numbers
vector<int> generateSequence(int start, int end) {
    vector<int> sequence;
    for (int i = start; i <= end; ++i) {
        sequence.push_back(i);
    }
    return sequence;
}

// Function to create a pattern based on the sequence
void createPattern(vector<int> sequence) {
    int n = sequence.size();
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                cout << sequence[i] << " ";
            } else if (i + j == n - 1) {
                cout << sequence[i] << " ";
            } else {
                cout << "  ";
            }
        }
        cout << endl;
    }
}

// Function to highlight a section of the code
void highlightSection(string section) {
    cout << "\n*highlighted section*" << section << "\n";
}

int main() {
    // Generate a sequence of numbers
    vector<int> numbers = generateSequence(1, 10);

    // Create a pattern using the sequence
    createPattern(numbers);

    // Highlight specific sections of the code
